SELECT name
FROM public_figures
WHERE followers_count > 100000;

SELECT value
FROM public_figure_statistics
WHERE key = 'tweet_count';

SELECT MAX(followers_count) AS max_followers
FROM public_figures
WHERE verified = 1;

SELECT MIN(value) AS min_followers
FROM user_metadata
WHERE key = 'followers_count';

SELECT name
FROM public_figures
WHERE followers_count = (SELECT MIN(followers_count) FROM public_figures);

SELECT name, followers_count
FROM public_figures
ORDER BY followers_count DESC;

SELECT key, COUNT(statistic_id) AS statistic_count, MAX(last_updated) AS last_updated_date
FROM public_figure_statistics
GROUP BY key;

SELECT key, value, tweet_id
FROM tweet_metadata
WHERE key = 'source';
